/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE mat_raw (
    id TEXT PRIMARY KEY,
    code TEXT,
    name TEXT,
    spec TEXT,
    new_code TEXT,
    new_name TEXT,
    status TEXT DEFAULT '未治理',
    source TEXT,
    created_at INTEGER
  );
CREATE TABLE mat_archive (
    id TEXT PRIMARY KEY,
    code TEXT UNIQUE,
    name TEXT,
    synonyms TEXT,
    category TEXT,
    raw_count INTEGER DEFAULT 0,
    created_at INTEGER
  );
CREATE TABLE categories (
    id TEXT PRIMARY KEY,
    code TEXT,
    l1 TEXT, l2 TEXT, l3 TEXT, l4 TEXT,
    status TEXT DEFAULT '正常',
    created_at INTEGER
  , key_attrs TEXT DEFAULT '');
CREATE TABLE goods_std (
    id TEXT PRIMARY KEY,
    code TEXT UNIQUE,
    name TEXT,
    category TEXT,
    attrs TEXT,
    raw_count INTEGER DEFAULT 0,
    mat_code TEXT,
    created_at INTEGER
  );
CREATE TABLE mapping (
    id TEXT PRIMARY KEY,
    goods_code TEXT,
    goods_name TEXT,
    mat_code TEXT,
    mat_name TEXT,
    type TEXT,
    method TEXT,
    created_at INTEGER
  );
COMMIT;
